.erp-table-container {
  width: 100%;
  height: 100%;
  overflow: auto;
  font-family: -apple-system, sans-serif;
}

table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
  table-layout: fixed;
}

th {
  background-color: #f1f5f9;
  color: #0f172a;
  font-weight: bold;
  text-align: center;
  padding: 10px 5px;
  border: 1px solid #cbd5e1;
  position: sticky;
  top: 0;
  z-index: 10;
  word-wrap: break-word;
}

td {
  padding: 8px 5px;
  border: 1px solid #cbd5e1;
  color: #1e293b;
  vertical-align: middle;
  text-align: center;
  word-wrap: break-word;
  overflow-wrap: break-word;
  white-space: normal;
}

td:nth-child(2), td:nth-child(3), td:nth-child(14), td:nth-child(15) {
  text-align: left;
}

.col-highlight {
  font-weight: bold;
  color: #0369a1;
}

.text-red {
  color: #dc2626;
  font-weight: bold;
}

.text-green {
  color: #15803d;
  font-weight: bold;
}

.btn-delete {
  background: #ef4444;
  color: white;
  border: none;
  padding: 4px 8px;
  border-radius: 4px;
  cursor: pointer;
}

