appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    renderTable(model.data);
  });
});
function renderTable(data) {
  const tbody = document.getElementById('tableBody');
  if (!data || data.length === 0) {
    tbody.innerHTML = '<tr><td colspan="15" style="text-align:center; padding: 30px; color: #64748b;">Bảng xuất kho trống...</td></tr>';
    return;
  }
  const groups = {};
  data.forEach(item => {
    const key = String(item.id_vat_tu) + '_' + String(item.id_mau_sac || 'NO') + '_' + String(item.ly_do) + '_' + String(item.nguon_du_lieu);
    if (!groups[key]) {
      groups[key] = {
        items: [],
        tong_yc_xuat: 0,
        ton_thuc_te: parseFloat(item.ton_thuc_te) || 0,
        ton_kha_dung_dau_vao: parseFloat(item.ton_kha_dung_hien_tai) || 0,
        // Kế thừa tồn
        da_xuat_tong: parseFloat(item.da_xuat) || 0
      };
    }
    groups[key].items.push(item);
    groups[key].tong_yc_xuat += parseFloat(item.yeu_cau_xuat) || 0;
  });
  let html = '';
  for (const key in groups) {
    const group = groups[key];
    const rowSpan = group.items.length;
    group.items.forEach((item, index) => {
      let bgColor = item.mau_nen || '#ffffff';
      let st = `style="background-color: ${bgColor};"`; // ÉP MÀU TỪNG Ô

      html += `<tr>`;
      html += `<td ${st}><button class="btn-delete" onclick="window.deleteRow('${item.id_tam}')">X</button></td>`;
      html += `<td ${st}><strong>${item.nguon_du_lieu}</strong></td>`;
      html += `<td ${st}>${item.vat_tu}</td>`;
      let mauHienThi = item.mau_sac;
      if (!mauHienThi || mauHienThi === 'NR' || mauHienThi === 'Không màu' || mauHienThi === 'null') mauHienThi = '\\';
      html += `<td ${st}>${mauHienThi}</td>`;
      html += `<td ${st}>${item.dvt || '\\'}</td>`;
      html += `<td ${st}>${item.dinh_muc > 0 ? item.dinh_muc : '\\'}</td>`;
      html += `<td ${st}>${item.is_bom ? item.tong_can_bom : '\\'}</td>`;
      html += `<td ${st}>${item.yeu_cau_xuat != null ? item.yeu_cau_xuat : 0}</td>`;
      if (index === 0) {
        html += `<td rowspan="${rowSpan}" class="col-merge" ${st}>${group.ton_thuc_te}</td>`;
        html += `<td rowspan="${rowSpan}" class="col-merge" ${st}><strong>${group.ton_kha_dung_dau_vao}</strong></td>`;
        let colorYC = group.tong_yc_xuat > group.ton_kha_dung_dau_vao ? 'text-red' : '';
        html += `<td rowspan="${rowSpan}" class="col-merge ${colorYC}" ${st}><strong>${group.tong_yc_xuat}</strong></td>`;
      }
      let slThucXuat = item.thuc_xuat != null ? item.thuc_xuat : 0;
      let thucXuatTextClass = slThucXuat < (item.yeu_cau_xuat || 0) && bgColor === '#fee2e2' ? 'text-red' : 'text-green';
      html += `<td class="col-highlight ${thucXuatTextClass}" ${st}>${slThucXuat}</td>`;
      html += `<td ${st}>${item.da_xuat != null ? item.da_xuat : 0}</td>`;
      html += `<td ${st}>${item.ly_do || ''}</td>`;
      html += `<td ${st}>${item.ghi_chu || ''}</td>`;
      html += `</tr>`;
    });
  }
  tbody.innerHTML = html;
}
window.deleteRow = function (idTam) {
  appsmith.updateModel({
    idXoa: idTam
  });
  appsmith.triggerEvent("onXoaDong");
};

